module bin2gray(
    input [3:0] invalid_bin,

    output reg [3:0] gray_out
);

always @(*)
begin
    gray_out[3] = invalid_bin[3];
    gray_out[2] = invalid_bin[3] ^ invalid_bin[2];
    gray_out[1] = invalid_bin[2] ^ invalid_bin[1];
    gray_out[0] = invalid_bin[1] ^ invalid_bin[0];
end

endmodule
